module RefModule(input wire [3:0] in, input wire [1:0] s, output wire out);reg [3:0] final_sig;
    always @(in or s)
        case (s)
            2'b00: final_sig = in[0];
            2'b01: final_sig = in[1];
            2'b10: final_sig = in[2];
            2'b11: final_sig = in[3];
            default: final_sig = 4'b0;
        endcase
    assign out = final_sig;
endmodule
